   352→      if (value === null) {
   353→        value = config.defaultValue;
   354→      }
   355→      
   356→      // Transform the value if needed
   357→      if (config.transform && config.transform !== 'none') {
   358→        value = transformFieldValue(value, config.transform, config.valueMapping);
   359→      }
   360→      
   361→      mapped[devOpsField] = value;
   362→    });
