   304→// API: Azure DevOps CREATE
   305→// --------------------
   306→function ensureAllowedTags(tagsInput) {
   307→  const allowed = new Set(['Grand Rapids', 'IT GR Track']);
   308→
   309→  let tags = [];
   310→
   311→  if (Array.isArray(tagsInput)) {
   312→    tags = tagsInput.map(t => String(t).trim()).filter(Boolean);
   313→  } else if (typeof tagsInput === 'string') {
   314→    tags = tagsInput
   315→      .split(';')
   316→      .map(t => t.trim())
   317→      .filter(Boolean);
   318→  }
   319→
   320→  // Check if at least one allowed tag exists
   321→  const hasAllowed = tags.some(t => allowed.has(t));
   322→
   323→  // If none present, automatically add Grand Rapids
   324→  if (!hasAllowed) {
   325→    tags.push('Grand Rapids');
   326→  }
   327→
   328→  // Remove duplicates
   329→  tags = [...new Set(tags)];
   330→
   331→  // Azure expects semicolon separated string
   332→  return tags.join('; ');
   333→}
